using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace MyApp.Controllers
{
    public class FileController : ControllerBase
    {
        [HttpGet("file/{filename}")]
        public IActionResult GetFile(string filename)
        {
            // Validate file path
            if (!Path.IsPathRooted(filename))
            {
                return BadRequest();
            }

            var allowedDirectories = new[] { "uploads", "images", "pdfs" };
            var directory = Path.GetDirectoryName(filename);
            if (!allowedDirectories.Contains(directory))
            {
                return Forbid();
            }

            // Read file content and set appropriate content type
            var fileContent = File.ReadAllBytes(filename);
            var contentType = GetContentType(filename);

            return File(fileContent, contentType);
        }

        private string GetContentType(string filename)
        {
            // TODO: Implement logic to determine the appropriate content type for the file
            // based on its extension.
            return "application/octet-stream";
        }
    }
}